def get_quote(policy_number, customer_name):
    wsdl_url = "https://third-party-insurance-service-wsdl-url"
    client = Client(wsdl=wsdl_url)

    # Assuming the service has a method called 'get_quote' that takes policy number and customer name as arguments
    get_quote_op = client.service.get_quote

    soap_body = f"""
        <soapenv:Envelope xmlns:soapenv="http://schemas.xmlsoap.org/soap/envelope/" xmlns:ins="http://www.third-party-insurance.com/namespace">
            <soapenv:Header/>
            <soapenv:Body>
                <ins:get_quote>
                    <policyNumber>{policy_number}</policyNumber>
                    <customerName>{customer_name}</customerName>
                </ins:get_quote>
            </soapenv:Body>
        </soapenv:Envelope>
    """

    response = get_quote_op(soap_body)
    return response

